package ratelimiter

import (
	"sync"
	"time"
)

// tokenBucketLimiter implements Limiter using a token bucket per key.
type tokenBucketLimiter struct {
	cfg   Config
	clock Clock

	mu      sync.Mutex
	buckets map[string]*bucket
}

// bucket holds the per‑key state.
type bucket struct {
	tokens float64
	last   time.Time
}

// realClock implements Clock using the actual system clock.
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }

// newLimiter returns a Limiter implementation.
func newLimiter(cfg Config, clock Clock) Limiter {
	// Default burst to Rate when not specified.
	if cfg.Burst == 0 {
		cfg.Burst = cfg.Rate
	}
	if clock == nil {
		clock = realClock{}
	}
	return &tokenBucketLimiter{
		cfg:     cfg,
		clock:   clock,
		buckets: make(map[string]*bucket),
	}
}

// refillRate returns the number of tokens added per nanosecond.
func (l *tokenBucketLimiter) refillRate() float64 {
	// Rate per Window duration.
	return float64(l.cfg.Rate) / float64(l.cfg.Window)
}

// Allow checks whether a request for the given key can proceed.
func (l *tokenBucketLimiter) Allow(key string) bool {
	now := l.clock.Now()

	l.mu.Lock()
	b, ok := l.buckets[key]
	if !ok {
		// First request for this key: start with a full burst.
		b = &bucket{
			tokens: float64(l.cfg.Burst),
			last:   now,
		}
		l.buckets[key] = b
	}

	// Refill tokens based on elapsed time.
	elapsed := now.Sub(b.last)
	if elapsed > 0 {
		added := float64(elapsed.Nanoseconds()) * l.refillRate()
		b.tokens += added
		if b.tokens > float64(l.cfg.Burst) {
			b.tokens = float64(l.cfg.Burst)
		}
		b.last = now
	}

	if b.tokens >= 1.0 {
		b.tokens -= 1.0
		l.mu.Unlock()
		return true
	}
	l.mu.Unlock()
	return false
}

// Reset clears the state for a specific key.
func (l *tokenBucketLimiter) Reset(key string) {
	l.mu.Lock()
	delete(l.buckets, key)
	l.mu.Unlock()
}
EOF
